import json, sys
content = sys.stdin.read()
start = content.index('{')
end = content.rindex('}') + 1
data = json.loads(content[start:end])
with open('after-cpm-packages.json', 'w') as f:
    json.dump(data, f, indent=2)

# Compare with baseline
with open('baseline-packages.json') as f:
    baseline = json.load(f)

def get_pkgs(data):
    pkgs = {}
    for proj in data['projects']:
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                pkgs[pkg['id']] = pkg['resolvedVersion']
    return pkgs

b = get_pkgs(baseline)
a = get_pkgs(data)
if b == a:
    print('All packages resolve identically. Conversion is version-neutral.')
else:
    for k in set(list(b.keys()) + list(a.keys())):
        bv = b.get(k, 'MISSING')
        av = a.get(k, 'MISSING')
        if bv != av:
            print(f'CHANGED: {k}: {bv} -> {av}')
"

